Почему в этой программе при посыле сигнала SIGUSR1 не выводится строка "Caught SIGUSR1"?
#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <pthread.h>
#include <unistd.h>

pthread_t thread1;
sigset_t set;
int thread_pid;
void *thread_func(void *args) {
    thread_pid = getpid();
    printf("Thread started.\n");
    while(1) {
        int signum;
        sigwait(&set, &signum);
        printf("Received signal %d\n", signum);
  if (signum == SIGUSR1){
    break;
  }
    }
    sleep(2);
    printf("ending thread!\n");
    pthread_exit(NULL);
}


void sig_handler(int signum){
  printf("Caught SIGUSR1\n");
}


int main() {

    signal(SIGUSR1, sig_handler);
    signal(SIGUSR2, SIG_IGN);


    sigemptyset(&set);
    sigaddset(&set, SIGTERM);
    sigaddset(&set, SIGINT);
    sigaddset(&set, SIGUSR1);
    if(pthread_create(&thread1, NULL, thread_func, NULL)) {
        printf("Error creating thread\n");
        return 1;
    }

    printf("Main thread started. PID: %d\n", getpid());

    int i = 0;
    while(1) {
        printf("Main thread running %d\n", i);
  pthread_kill(thread1, SIGUSR2);
        i++;
  if (i == 3){
    pthread_kill(thread1, SIGUSR1);
    break;
  }
        sleep(2);
    }
    sleep(1);
    pthread_join(thread1, NULL);
    printf("main is ending\n");
    return 0;
}

add pause and stop buttons: package main

import (
    "os"
    "time"
    "log"
	"net/http"

    "gioui.org/app"
    "gioui.org/io/system"
    "gioui.org/layout"
    "gioui.org/op"
    "gioui.org/unit"
    "gioui.org/widget"
    "gioui.org/widget/material"
    "gioui.org/font/gofont"

    "github.com/hajimehoshi/oto/v2"
    "github.com/hajimehoshi/go-mp3"
)

func main() {
    go func() {
        w := app.NewWindow(
            app.Title("mp3 reader"),
            app.Size(unit.Dp(350), unit.Dp(500)),
        )

        var ops op.Ops
        for event := range w.Events() {
            switch event := event.(type) {
            case system.DestroyEvent:
                os.Exit(0)
            case system.FrameEvent:
                event.Frame(frame(layout.NewContext(&ops, event)))
            }
        }
    }()
    app.Main()
}

type (
    // C quick alias for Context.
    C = layout.Context
    // D quick alias for Dimensions.
    D = layout.Dimensions
)

var (
    th       = material.NewTheme(gofont.Collection())
    topLabel = "mp3 reader"
    playBtn  = widget.Clickable{}
	url      string = "https://qurango.net/radio/ahmad_khader_altarabulsi"
)

// frame lays out the entire frame and returns the resultant ops buffer.
func frame(gtx C) *op.Ops {

    layout.Center.Layout(gtx, func(gtx C) D {

        gtx.Constraints.Max.X = gtx.Dp(unit.Dp(300))
        return layout.Flex{Axis: layout.Vertical}.Layout(gtx,
            layout.Rigid(func(gtx C) D {
                label := material.H5(th, topLabel)
                return label.Layout(gtx)
            }),
            layout.Rigid(func(gtx C) D {
                return material.Button(th, &playBtn, "Play").Layout(gtx)
            }),

        )
    })

    if playBtn.Clicked() {
        go func() {
			var err error
			var response *http.Response
			if response, err = http.Get(url); err != nil {
				log.Fatal(err)
			}

			d, err := mp3.NewDecoder(response.Body)
			if err != nil {
				return
			}

			c, ready, err := oto.NewContext(d.SampleRate(), 2, 2)
			if err != nil {
				return
			}
			<-ready

			p := c.NewPlayer(d)
			defer p.Close()
			p.Play()

			for {
				time.Sleep(time.Second)
				if !p.IsPlaying() {
					break
				}
			}
			return

        }()
    }
    return gtx.Ops
}

in this same p5.js code, can you make a white glowing ball that moves along the shapes from beginning to end at a speed of .5ms ?  Please also give this ball a slider that adjust speed: 
let sidesSlider;
let sizeSlider;
let spiralSlider;
let reflectionSlider;
let gradientSlider;
let randomMovementSlider; // New slider for random movement intensity
let bgColorSlider; // New slider for background color
let dragging = false;
let shapeCenter;
let sliderArea;

function setup() {
  createCanvas(600, 800);
  sidesSlider = createSlider(3, 20, 3);
  sidesSlider.position(30, 40);

  sizeSlider = createSlider(50, min(width, height) / 2, min(width, height) / 4);
  sizeSlider.position(30, 70);

  spiralSlider = createSlider(0, 50, 1);
  spiralSlider.position(30, 100);

  reflectionSlider = createSlider(0, 3, 0);
  reflectionSlider.position(30, 130);

  gradientSlider = createSlider(0, 255, 128);
  gradientSlider.position(30, 160);

  randomMovementSlider = createSlider(0, 50, 5); // Initialize the new slider
  randomMovementSlider.position(30, 190);

  bgColorSlider = createSlider(0, 255, 240); // Initialize the new slider for background color
  bgColorSlider.position(30, 220);

  textAlign(CENTER, CENTER);
  shapeCenter = createVector(width / 2 + 100, height / 2 + 100); // Updated shape center position

  sliderArea = {
    x: 20,
    y: 20,
    width: 140,
    height: 220, // Updated height to include new slider
  };

  colorMode(HSB, 255);
}

function draw() {
  let bgColor = bgColorSlider.value(); // Get value of new slider
  background(bgColor, 255, 255);

  // Draw slider area rectangle
  fill(255);
  stroke(200);
  rect(sliderArea.x, sliderArea.y, sliderArea.width, sliderArea.height);

  // Update shape position when dragging
  if (dragging) {
    shapeCenter.x = mouseX;
    shapeCenter.y = mouseY;
  }

  let sides = sidesSlider.value();
  let size = sizeSlider.value();
  let spiralCount = spiralSlider.value();
  let reflection = reflectionSlider.value();
  let gradient = gradientSlider.value();
  let randomMovement = randomMovementSlider.value(); // Get value of new slider

  translate(shapeCenter.x, shapeCenter.y);

  drawSpirals(sides, size, spiralCount, gradient, randomMovement);

  // Render reflections
  switch (reflection) {
    case 1:
      scale(-1, 1);
      drawSpirals(sides, size, spiralCount, gradient, randomMovement);
      break;
    case 2:
      scale(1, -1);
      drawSpirals(sides, size, spiralCount, gradient, randomMovement);
      break;
    case 3:
      scale(-1, 1);
      drawSpirals(sides, size, spiralCount, gradient, randomMovement);
      scale(1, -1);
      drawSpirals(sides, size, spiralCount, gradient, randomMovement);
      break;
  }

  checkForDrag();
}

function drawSpirals(sides, size, spiralCount, gradient, randomMovement) {
  for (let i = 0; i < spiralCount; i++) {
    push();
    rotate((TWO_PI / spiralCount) * i);
    translate((size * i) / spiralCount, 0);
    strokeWeight(4);
    stroke(gradient, 255, 255);
    noFill();
    drawShape(sides, size, randomMovement);
    pop();
  }
}

function drawShape(sides, radius, randomMovement) {
  let angle = TWO_PI / sides;
  let offset = randomMovement; // Use randomMovement for offset
  beginShape();
  for (let i = 0; i < sides; i++) {
    let x = (radius + random(-offset, offset)) * cos(angle * i);
    let y = (radius + random(-offset, offset)) * sin(angle * i);
    vertex(x, y);
  }
  endShape(CLOSE);
}

function checkForDrag() {
  const minDist = sizeSlider.value() * spiralSlider.value() / 2;
  if (
    mouseX > sliderArea.x &&
    mouseX < sliderArea.x + sliderArea.width &&
    mouseY > sliderArea.y &&
    mouseY < sliderArea.y + sliderArea.height
  ) {
    dragging = false;
    cursor('default');
  } else if (dist(mouseX, mouseY, shapeCenter.x, shapeCenter.y) < minDist) {
    cursor('grab');
    if (mouseIsPressed) {
      dragging = true;
      cursor('grabbing');
    }
  } else {
    dragging = false;
    cursor('default');
  }
}

function mouseReleased() {
  dragging = false;
  cursor('default');
}

