class AuthDataSource with HttpResponseValidator implements IAuthDataSource {
  @override
  Future<Response> checkAccountByPhoneNumber(String accountNumber) async {
    final response = await clientHttpAuth.get(
        routes[Routes.checkAccountByPhoneNumber]!,
        options: Options(validateStatus: (status) => status! <= 500),
        queryParameters: {"account": accountNumber});

    return response;
  }

  @override
  Future<void> sendOtp(String accountNumber) async {
    await clientHttpAuth.post(
      routes[Routes.sendOtp]!,
      data: {"account": accountNumber},
    );
  }

  @override
  Future<Response> register(
    String idd,
    String phoneNumber,
    String gender,
    String typeId,
    String firstName,
    String lastName,
    String email,
    String idNumber,
    String birthDay,
    String verificationCode,
    int weight,
    int height,
    String emsFirstName,
    String emsLastName,
    String emsPhoneNumber,
    String emsRelationType,
  ) async {
    //? note : convert own dob to system dob
    var birth = birthDay.split('/');

    final response = await clientHttpAuth.post(
      routes[Routes.register]!,
      options: Options(validateStatus: (status) => status! <= 500),
      data: {
        "SSId": idNumber,
        "SSIdType": typeId,
        "idd": idd,
        "firstName": firstName,
        "lastName": lastName,
        "gender": gender,
        "dateOfBirth": "${birth[2]}-${birth[1]}-${birth[0]}T12:07:36.812Z",
        "maritalStatusType": "Married",
        "weight": weight,
        "height": height,
        "language": [],
        "verificationCode": verificationCode,
        "firstNameEms": emsFirstName,
        "lastNameEms": emsLastName,
        emsRelationType.isNotEmpty ? "relationshipEms" : emsRelationType: null,
        "phoneNumberEms": emsPhoneNumber,
        "registerType": "Phone",
        "phoneNumber": phoneNumber,
        "email": email
      },
    );
    return response;
  }

  @override
  Future<AuthInfoEntity> loginWithOtp(String phoneNumber, String otp) async {
    final response =
        await clientHttpAuthLogin.post(routes[Routes.loginWithOtp]!,
            data: {
              "client_id": Environment.authenticatorCliendId,
              "client_secret": Environment.authenticatorClientSecret,
              "grant_type": "password",
              "username": phoneNumber,
              "smsCode": otp,
            },
            options: Options(contentType: Headers.formUrlEncodedContentType));
    AuthInfoEntity authinfo = AuthInfoEntity(
      accessToken: response.data['access_token'],
      expiresIn: response.data['expires_in'].toString(),
      tokenType: response.data['token_type'],
      refreshToken: response.data['refresh_token'],
    );
    return authinfo;
  }

  @override
  Future<UserInfo> getPatientInfo(String token) async {
    final response = await clientHttpAuth.get(routes[Routes.getPatientInfo]!);
    UserInfo userInfo = UserInfo.fromJson(response.data);
    return userInfo;
  }
}
